#include<bits/stdc++.h>
using namespace std;
int p[1000010],d[1000010],n,m,cnt[1000010];
vector<int> mp[1000010];
void dfs1(int x)
{
    d[x]=d[p[x]]+1;
    if(cnt[x]==0)
    {
        m++;
    }
    for(int i:mp[x])
    {
        dfs1(i);
    }
}
int dfs2(int x)
{
    if(cnt[x])
    {
        return d[x]+1;
    }
    if(x==0)
    {
        return 0;
    }
    cnt[p[x]]--;
    return dfs2(p[x]);
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&p[i]);
        cnt[p[i]]++;
        mp[p[i]].push_back(i);
    }
    d[0]=-1;
    dfs1(0);
    for(int i=1;i<=m;i++)
    {
        int x;
        scanf("%d",&x);
        printf("%d\n",dfs2(x));
    }
    return 0;
}
